// ─── CharCreatePanel ─────────────────────────────────────────────────────────

class CharCreatePanel extends UIPanel {
  constructor(onComplete) {
    super('panel-char-create', { trapFocus: false, zLayer: 'panel' });
    this._onComplete = onComplete;

    this._step = 0;
    this._steps = ['Race', 'Attributes', 'Appearance', 'Background', 'Trees', 'Feat', 'Confirm'];

    // Selections accumulate across steps
    this._sel = {
      raceId:         'human',
      freeAttrTarget: null,   // attr key if race has free point
      attributes:     null,   // computed after race selection
      bodyType:       1,
      name:           '',
      skinColor:      SKIN_COLORS[0],
      hairColor:      HAIR_COLORS[3],
      eyeColor:       EYE_COLORS[2],
      childhood:      null,
      adult:          null,
      trees:          [],
      feat:           null,
    };

    this._keyHandler = this._onKey.bind(this);
  }

  // ── Build ──────────────────────────────────────────────────────────────────

  build() {
    this.el.innerHTML = '';
    const root = document.createElement('div');
    root.className = 'cc-root';
    root.setAttribute('role', 'dialog');
    root.setAttribute('aria-label', 'Character Creation');

    root.appendChild(this._buildStepBar());

    const content = document.createElement('div');
    content.className = 'cc-content';
    this._mainEl = document.createElement('div');
    this._mainEl.className = 'cc-main';
    this._sideEl = document.createElement('div');
    this._sideEl.className = 'cc-side';
    content.appendChild(this._mainEl);
    content.appendChild(this._sideEl);
    root.appendChild(content);

    root.appendChild(this._buildNav());

    this.el.appendChild(root);

    document.addEventListener('keydown', this._keyHandler);
    this._renderStep();
    return this;
  }

  _buildStepBar() {
    const bar = document.createElement('div');
    bar.className = 'cc-steps';
    bar.id = 'cc-step-bar';
    this._steps.forEach((label, i) => {
      const item = document.createElement('div');
      item.className = 'cc-step-item';
      item.dataset.stepIdx = String(i);

      const dot = document.createElement('div');
      dot.className = 'cc-step-dot';
      dot.textContent = String(i + 1);

      const lbl = document.createElement('div');
      lbl.className = 'cc-step-label';
      lbl.textContent = label;

      item.appendChild(dot);
      item.appendChild(lbl);
      bar.appendChild(item);
    });
    return bar;
  }

  _buildNav() {
    const nav = document.createElement('div');
    nav.className = 'cc-nav';
    nav.id = 'cc-nav';

    this._backBtn = document.createElement('button');
    this._backBtn.className = 'cc-btn';
    this._backBtn.id = 'cc-btn-back';
    this._backBtn.textContent = 'Back';
    this._backBtn.addEventListener('click', () => this._goBack());

    this._centerLabel = document.createElement('span');
    this._centerLabel.className = 'cc-nav-center';

    this._nextBtn = document.createElement('button');
    this._nextBtn.className = 'cc-btn primary';
    this._nextBtn.id = 'cc-btn-next';
    this._nextBtn.textContent = 'Next';
    this._nextBtn.addEventListener('click', () => this._goNext());

    nav.appendChild(this._backBtn);
    nav.appendChild(this._centerLabel);
    nav.appendChild(this._nextBtn);
    return nav;
  }

  // ── Step routing ──────────────────────────────────────────────────────────

  _renderStep() {
    this._updateStepBar();
    this._updateNavButtons();

    const stepFns = [
      () => this._renderRaceStep(),
      () => this._renderAttributesStep(),
      () => this._renderAppearanceStep(),
      () => this._renderBackgroundStep(),
      () => this._renderTreesStep(),
      () => this._renderFeatStep(),
      () => this._renderConfirmStep(),
    ];

    const fn = stepFns[this._step];
    if (fn) fn();
  }

  _updateStepBar() {
    const bar = document.getElementById('cc-step-bar');
    if (!bar) return;
    const items = bar.querySelectorAll('.cc-step-item');
    items.forEach((item, i) => {
      const dot = item.querySelector('.cc-step-dot');
      item.classList.toggle('active', i === this._step);
      dot.classList.toggle('active', i === this._step);
      dot.classList.toggle('done', i < this._step);
    });
  }

  _updateNavButtons() {
    if (!this._backBtn || !this._nextBtn) return;
    this._backBtn.disabled = this._step === 0;
    const isLast = this._step === this._steps.length - 1;
    this._nextBtn.textContent = isLast ? 'Create Hero' : 'Next';
    this._nextBtn.id = isLast ? 'cc-btn-create' : 'cc-btn-next';
    this._centerLabel.textContent = `Step ${this._step + 1} of ${this._steps.length}`;
  }

  _goNext() {
    if (!this._validateStep()) return;
    if (this._step === this._steps.length - 1) {
      this._createHero();
      return;
    }
    this._step++;
    this._renderStep();
    this._mainEl.scrollTop = 0;
  }

  _goBack() {
    if (this._step > 0) {
      this._step--;
      this._renderStep();
      this._mainEl.scrollTop = 0;
    }
  }

  _validateStep() {
    switch (this._step) {
      case 0: return !!this._sel.raceId;
      case 1: return true;
      case 2: return !!this._sel.name?.trim();
      case 3: return !!this._sel.childhood && !!this._sel.adult;
      case 4: return this._sel.trees.length === 3;
      case 5: return !!this._sel.feat;
      default: return true;
    }
  }

  // ── Step 1: Race ──────────────────────────────────────────────────────────

  _renderRaceStep() {
    this._mainEl.innerHTML = `
      <h2 class="cc-step-title">Choose Your Race</h2>
      <p class="cc-step-desc">Select the race that defines your heritage and racial traits.</p>
    `;

    const grid = document.createElement('div');
    grid.className = 'cc-race-grid';
    grid.id = 'cc-race-grid';

    const races = CharacterSystem.getPlayableRaces();
    races.forEach(race => {
      const card = document.createElement('button');
      card.type = 'button';
      card.className = 'cc-race-card' + (race.unlockCondition ? ' locked' : '');
      card.dataset.raceId = race.id;
      card.setAttribute('tabindex', '0');
      card.disabled = !!race.unlockCondition;

      const bonusText = this._formatBonuses(race.attributeBonuses);

      card.innerHTML = `
        <div class="cc-race-name">${race.name}</div>
        <div class="cc-race-rarity ${race.rarity}">${race.rarity}</div>
        ${bonusText ? `<div class="cc-race-bonuses">${bonusText}</div>` : ''}
        ${race.unlockCondition ? '<div class="cc-lock-icon">&#x1F512;</div>' : ''}
      `;

      if (!race.unlockCondition) {
        card.addEventListener('click', () => {
          this._sel.raceId = race.id;
          // Reset free attr
          this._sel.freeAttrTarget = null;
          // Recompute base attributes
          this._sel.attributes = this._computeRaceAttributes(race);
          grid.querySelectorAll('.cc-race-card').forEach(c => c.classList.remove('selected'));
          card.classList.add('selected');
          this._updateRacePreview(race);
        });
      }

      if (race.id === this._sel.raceId) {
        card.classList.add('selected');
      }

      grid.appendChild(card);
    });

    this._mainEl.appendChild(grid);

    // Update side preview for currently selected race
    const selRace = races.find(r => r.id === this._sel.raceId);
    if (selRace) {
      this._updateRacePreview(selRace);
    }
  }

  _formatBonuses(bonuses) {
    if (!bonuses) return '';
    return Object.entries(bonuses)
      .map(([k, v]) => `${v > 0 ? '+' : ''}${v} ${k.charAt(0).toUpperCase() + k.slice(1)}`)
      .join(', ');
  }

  _computeRaceAttributes(race) {
    const base = { ...race.baseAttributes };
    const bonuses = race.attributeBonuses ?? {};
    const result = {};
    for (const k of Object.keys(base)) {
      result[k] = base[k] + (bonuses[k] ?? 0);
    }
    return result;
  }

  _updateRacePreview(race) {
    this._sideEl.innerHTML = '';

    const title = document.createElement('div');
    title.className = 'cc-preview-title';
    title.textContent = race.name;
    this._sideEl.appendChild(title);

    // Description
    const desc = document.createElement('p');
    desc.style.cssText = 'font-size: clamp(0.65rem,1.1vw,0.78rem); color:#7a6a40; margin:0 0 12px 0;';
    desc.textContent = race.description;
    this._sideEl.appendChild(desc);

    // Attributes
    const attrSection = document.createElement('div');
    attrSection.className = 'cc-preview-section';
    attrSection.textContent = 'Attributes';
    this._sideEl.appendChild(attrSection);

    const attrs = ['might', 'agility', 'intellect', 'wisdom', 'endurance', 'presence'];
    const base = race.baseAttributes;
    const bonuses = race.attributeBonuses ?? {};
    attrs.forEach(k => {
      const bonus = bonuses[k] ?? 0;
      const total = (base[k] ?? 10) + bonus;
      const row = document.createElement('div');
      row.className = 'cc-attr-row';
      const bonusCls = bonus > 0 ? 'bonus' : bonus < 0 ? 'malus' : '';
      row.innerHTML = `
        <span class="cc-attr-label">${k.charAt(0).toUpperCase() + k.slice(1)}</span>
        <span class="cc-attr-val ${bonusCls}">${total}${bonus !== 0 ? ` (${bonus > 0 ? '+' : ''}${bonus})` : ''}</span>
      `;
      this._sideEl.appendChild(row);
    });

    // Traits
    if (race.racialTraits?.length > 0) {
      const traitSection = document.createElement('div');
      traitSection.className = 'cc-preview-section';
      traitSection.style.marginTop = '12px';
      traitSection.textContent = 'Racial Traits';
      this._sideEl.appendChild(traitSection);

      race.racialTraits.forEach(trait => {
        const t = document.createElement('div');
        t.className = 'cc-preview-trait';
        t.innerHTML = `
          <div class="cc-preview-trait-name">${trait.name}</div>
          <div class="cc-preview-trait-desc">${trait.description}</div>
        `;
        this._sideEl.appendChild(t);
      });
    }

    // Unlock condition
    if (race.unlockCondition) {
      const unlock = document.createElement('p');
      unlock.style.cssText = 'font-size:0.68rem; color:#6a4a2a; margin-top:10px; border-top:1px solid rgba(200,160,32,0.15); padding-top:8px;';
      unlock.textContent = 'Locked: ' + race.unlockCondition;
      this._sideEl.appendChild(unlock);
    }
  }

  // ── Step 2: Attributes ────────────────────────────────────────────────────

  _renderAttributesStep() {
    const race = CharacterSystem.getRace(this._sel.raceId);
    if (!race) return;

    if (!this._sel.attributes) {
      this._sel.attributes = this._computeRaceAttributes(race);
    }

    const hasFreePoint = race.racialTraits?.some(t => t.id === 'adaptable');

    this._mainEl.innerHTML = `
      <h2 class="cc-step-title">Starting Attributes</h2>
      <p class="cc-step-desc">Your base attributes come from your race. Hover to see derived abilities.</p>
    `;

    if (hasFreePoint) {
      const row = document.createElement('div');
      row.className = 'cc-free-point-row';
      row.innerHTML = `
        <span class="cc-free-point-label">Adaptable: Assign +1 free attribute point to:</span>
        <select class="cc-free-point-select" id="cc-free-attr-select">
          <option value="">-- Choose --</option>
          <option value="might">Might</option>
          <option value="agility">Agility</option>
          <option value="intellect">Intellect</option>
          <option value="wisdom">Wisdom</option>
          <option value="endurance">Endurance</option>
          <option value="presence">Presence</option>
        </select>
      `;
      this._mainEl.appendChild(row);

      const sel = row.querySelector('#cc-free-attr-select');
      if (this._sel.freeAttrTarget) sel.value = this._sel.freeAttrTarget;
      sel.addEventListener('change', () => {
        this._sel.freeAttrTarget = sel.value || null;
        this._renderAttributeTable(race);
      });
    }

    this._renderAttributeTable(race);

    // Side: derived abilities
    this._updateAttrSidePanel(race);
  }

  _renderAttributeTable(race) {
    const old = this._mainEl.querySelector('#cc-attr-table');
    if (old) old.remove();

    const base = this._sel.attributes ?? this._computeRaceAttributes(race);
    const freeTarget = this._sel.freeAttrTarget;

    const table = document.createElement('div');
    table.className = 'cc-attrs-table';
    table.id = 'cc-attr-table';

    // Header row
    ['Attribute', 'Base', 'Bonus', 'Total'].forEach(h => {
      const el = document.createElement('div');
      el.className = 'cc-attr-head';
      el.textContent = h;
      table.appendChild(el);
    });

    const attrs = ['might', 'agility', 'intellect', 'wisdom', 'endurance', 'presence'];
    attrs.forEach(k => {
      const raceBonus = (race.attributeBonuses ?? {})[k] ?? 0;
      const freeBonus = freeTarget === k ? 1 : 0;
      const total     = (race.baseAttributes[k] ?? 10) + raceBonus + freeBonus;

      const nameEl = document.createElement('div');
      nameEl.className = 'cc-attr-name';
      nameEl.textContent = k.charAt(0).toUpperCase() + k.slice(1);

      const baseEl = document.createElement('div');
      baseEl.className = 'cc-attr-base';
      baseEl.textContent = race.baseAttributes[k] ?? 10;

      const bonusVal = raceBonus + freeBonus;
      const bonusEl  = document.createElement('div');
      bonusEl.className = 'cc-attr-bonus-cell';
      bonusEl.style.color = bonusVal > 0 ? '#6ab06a' : bonusVal < 0 ? '#b06a6a' : '#5a5040';
      bonusEl.textContent = bonusVal === 0 ? '—' : (bonusVal > 0 ? '+' : '') + bonusVal;

      const totalEl = document.createElement('div');
      totalEl.className = 'cc-attr-total-cell';
      totalEl.textContent = total;

      table.appendChild(nameEl);
      table.appendChild(baseEl);
      table.appendChild(bonusEl);
      table.appendChild(totalEl);
    });

    this._mainEl.appendChild(table);
  }

  _updateAttrSidePanel(race) {
    this._sideEl.innerHTML = '';

    const freeTarget = this._sel.freeAttrTarget;
    const attrs = this._sel.attributes ?? this._computeRaceAttributes(race);
    const freeBonus = {};
    if (freeTarget) freeBonus[freeTarget] = 1;
    const finalAttrs = {};
    for (const k of Object.keys(attrs)) {
      finalAttrs[k] = attrs[k] + (freeBonus[k] ?? 0);
    }

    const char = { attributes: finalAttrs, level: 1 };
    const derived = CharacterSystem.getDerivedAbilities(char);
    const prof = CharacterSystem.getProficiencyBonus(1);

    const title = document.createElement('div');
    title.className = 'cc-preview-title';
    title.textContent = 'Derived Abilities';
    this._sideEl.appendChild(title);

    const profRow = document.createElement('div');
    profRow.className = 'cc-attr-row';
    profRow.innerHTML = `<span class="cc-attr-label">Proficiency Bonus</span><span class="cc-attr-val">+${prof}</span>`;
    this._sideEl.appendChild(profRow);

    const abilities = ['athletics','acrobatics','stealth','arcana','history','insight','nature','perception','survival','persuasion','deception','intimidate','command'];
    abilities.forEach(a => {
      const val = derived[a];
      const row = document.createElement('div');
      row.className = 'cc-attr-row';
      row.innerHTML = `
        <span class="cc-attr-label">${a.charAt(0).toUpperCase() + a.slice(1)}</span>
        <span class="cc-attr-val">${val >= 0 ? '+' : ''}${val}</span>
      `;
      this._sideEl.appendChild(row);
    });

    // HP/Mana preview
    const endVal = finalAttrs.endurance ?? 10;
    const intVal = finalAttrs.intellect ?? 10;
    const hpPreview = 10 + Math.max(0, Math.floor((endVal - 10) / 2));
    const mpPreview = 10 + Math.max(0, Math.floor((intVal - 10) / 2));

    const divider = document.createElement('div');
    divider.style.cssText = 'border-top:1px solid rgba(200,160,32,0.15); margin:8px 0;';
    this._sideEl.appendChild(divider);

    [['Max HP (L1)', hpPreview], ['Max Mana (L1)', mpPreview]].forEach(([label, val]) => {
      const row = document.createElement('div');
      row.className = 'cc-attr-row';
      row.innerHTML = `<span class="cc-attr-label">${label}</span><span class="cc-attr-val">${val}</span>`;
      this._sideEl.appendChild(row);
    });
  }

  // ── Step 3: Appearance ────────────────────────────────────────────────────

  _renderAppearanceStep() {
    this._mainEl.innerHTML = `
      <h2 class="cc-step-title">Appearance</h2>
      <p class="cc-step-desc">Customize your hero's look.</p>
    `;

    // Name
    const nameRow = document.createElement('div');
    nameRow.className = 'cc-name-row';
    nameRow.innerHTML = `<label class="cc-name-label" for="cc-name-input">Hero Name</label>`;
    const nameInput = document.createElement('input');
    nameInput.type = 'text';
    nameInput.className = 'cc-name-input';
    nameInput.id = 'cc-name-input';
    nameInput.placeholder = 'Enter hero name...';
    nameInput.maxLength = 32;
    nameInput.value = this._sel.name || '';
    nameInput.addEventListener('input', () => { this._sel.name = nameInput.value; });
    nameRow.appendChild(nameInput);
    this._mainEl.appendChild(nameRow);

    // Body type
    const bodyTitle = document.createElement('div');
    bodyTitle.className = 'cc-attr-head';
    bodyTitle.style.margin = '16px 0 8px 0';
    bodyTitle.textContent = 'Body Type';
    this._mainEl.appendChild(bodyTitle);

    const bodyGrid = document.createElement('div');
    bodyGrid.className = 'cc-appearance-grid';
    BODY_TYPES.forEach(bt => {
      const card = document.createElement('button');
      card.type = 'button';
      card.className = 'cc-body-card' + (this._sel.bodyType === bt.id ? ' selected' : '');
      card.innerHTML = `<span class="cc-body-icon">&#x1F9CD;</span>${bt.label}`;
      card.addEventListener('click', () => {
        this._sel.bodyType = bt.id;
        bodyGrid.querySelectorAll('.cc-body-card').forEach(c => c.classList.remove('selected'));
        card.classList.add('selected');
      });
      bodyGrid.appendChild(card);
    });
    this._mainEl.appendChild(bodyGrid);

    // Colors
    const colorGroups = [
      { label: 'Skin Color',  key: 'skinColor', colors: SKIN_COLORS },
      { label: 'Hair Color',  key: 'hairColor', colors: HAIR_COLORS },
      { label: 'Eye Color',   key: 'eyeColor',  colors: EYE_COLORS  },
    ];

    colorGroups.forEach(({ label, key, colors }) => {
      const row = document.createElement('div');
      row.className = 'cc-color-row';
      const lbl = document.createElement('div');
      lbl.className = 'cc-color-label';
      lbl.textContent = label;
      row.appendChild(lbl);

      const swatches = document.createElement('div');
      swatches.className = 'cc-swatch-list';
      colors.forEach(color => {
        const sw = document.createElement('button');
        sw.type = 'button';
        sw.className = 'cc-swatch' + (this._sel[key] === color ? ' selected' : '');
        sw.style.background = color;
        sw.title = color;
        sw.setAttribute('aria-label', `${label} ${color}`);
        sw.addEventListener('click', () => {
          this._sel[key] = color;
          swatches.querySelectorAll('.cc-swatch').forEach(s => s.classList.remove('selected'));
          sw.classList.add('selected');
          this._updateAppearanceSide();
        });
        swatches.appendChild(sw);
      });
      row.appendChild(swatches);
      this._mainEl.appendChild(row);
    });

    this._updateAppearanceSide();
  }

  _updateAppearanceSide() {
    this._sideEl.innerHTML = '';
    const title = document.createElement('div');
    title.className = 'cc-preview-title';
    title.textContent = 'Preview';
    this._sideEl.appendChild(title);

    // Simple visual representation
    const preview = document.createElement('div');
    preview.style.cssText = `
      width: 80px; height: 120px;
      margin: 16px auto;
      background: ${this._sel.skinColor};
      border-radius: 8px 8px 4px 4px;
      position: relative;
      border: 2px solid rgba(200,160,32,0.3);
    `;
    // Head
    const head = document.createElement('div');
    head.style.cssText = `
      width: 48px; height: 48px;
      background: ${this._sel.skinColor};
      border-radius: 50%;
      position: absolute;
      top: -28px; left: 50%; transform: translateX(-50%);
      border: 2px solid rgba(200,160,32,0.3);
    `;
    // Eyes
    const eyeL = document.createElement('div');
    eyeL.style.cssText = `width:8px; height:8px; background:${this._sel.eyeColor}; border-radius:50%; position:absolute; top:16px; left:8px;`;
    const eyeR = document.createElement('div');
    eyeR.style.cssText = `width:8px; height:8px; background:${this._sel.eyeColor}; border-radius:50%; position:absolute; top:16px; right:8px;`;
    // Hair
    const hair = document.createElement('div');
    hair.style.cssText = `width:52px; height:16px; background:${this._sel.hairColor}; border-radius:50% 50% 0 0; position:absolute; top:0; left:50%; transform:translateX(-50%);`;
    head.appendChild(hair);
    head.appendChild(eyeL);
    head.appendChild(eyeR);
    preview.appendChild(head);
    this._sideEl.appendChild(preview);

    const name = this._sel.name?.trim() || 'Unnamed';
    const nameLbl = document.createElement('div');
    nameLbl.style.cssText = 'text-align:center; color:#c8a020; font-weight:600; font-size:0.85rem; margin-top:8px;';
    nameLbl.textContent = name;
    this._sideEl.appendChild(nameLbl);
  }

  // ── Step 4: Background ────────────────────────────────────────────────────

  _renderBackgroundStep() {
    this._mainEl.innerHTML = `
      <h2 class="cc-step-title">Background</h2>
      <p class="cc-step-desc">Your history shapes your starting bonuses.</p>
    `;

    this._mainEl.appendChild(this._buildBgGrid('Childhood Background', CHILDHOOD_BACKGROUNDS, 'childhood'));

    const div = document.createElement('hr');
    div.style.cssText = 'border:none; border-top:1px solid rgba(200,160,32,0.15); margin:20px 0;';
    this._mainEl.appendChild(div);

    this._mainEl.appendChild(this._buildBgGrid('Adult Background', ADULT_BACKGROUNDS, 'adult'));

    this._updateBackgroundSide();
  }

  _buildBgGrid(title, list, key) {
    const wrap = document.createElement('div');

    const h = document.createElement('div');
    h.className = 'cc-step-title';
    h.style.fontSize = 'clamp(0.82rem, 1.5vw, 1rem)';
    h.style.marginBottom = '10px';
    h.textContent = title;
    wrap.appendChild(h);

    const grid = document.createElement('div');
    grid.className = 'cc-bg-grid';

    list.forEach(bg => {
      const card = document.createElement('button');
      card.type = 'button';
      card.className = 'cc-bg-card' + (this._sel[key] === bg.id ? ' selected' : '');
      card.innerHTML = `
        <div class="cc-bg-name">${bg.name}</div>
        <div class="cc-bg-bonus">${bg.bonus}</div>
      `;
      card.addEventListener('click', () => {
        this._sel[key] = bg.id;
        grid.querySelectorAll('.cc-bg-card').forEach(c => c.classList.remove('selected'));
        card.classList.add('selected');
        this._updateBackgroundSide();
      });
      grid.appendChild(card);
    });

    wrap.appendChild(grid);
    return wrap;
  }

  _updateBackgroundSide() {
    this._sideEl.innerHTML = '';
    const title = document.createElement('div');
    title.className = 'cc-preview-title';
    title.textContent = 'Background';
    this._sideEl.appendChild(title);

    if (this._sel.childhood) {
      const bg = CHILDHOOD_BACKGROUNDS.find(b => b.id === this._sel.childhood);
      if (bg) {
        const el = document.createElement('div');
        el.className = 'cc-preview-trait';
        el.innerHTML = `<div class="cc-preview-trait-name">Childhood: ${bg.name}</div><div class="cc-preview-trait-desc">${bg.bonus}</div>`;
        this._sideEl.appendChild(el);
      }
    }
    if (this._sel.adult) {
      const bg = ADULT_BACKGROUNDS.find(b => b.id === this._sel.adult);
      if (bg) {
        const el = document.createElement('div');
        el.className = 'cc-preview-trait';
        el.innerHTML = `<div class="cc-preview-trait-name">Adult: ${bg.name}</div><div class="cc-preview-trait-desc">${bg.bonus}</div>`;
        this._sideEl.appendChild(el);
      }
    }

    if (!this._sel.childhood && !this._sel.adult) {
      const hint = document.createElement('p');
      hint.style.cssText = 'font-size:0.75rem; color:#5a4a2a;';
      hint.textContent = 'Select both a childhood and adult background.';
      this._sideEl.appendChild(hint);
    }
  }

  // ── Step 5: Skill Trees ───────────────────────────────────────────────────

  _renderTreesStep() {
    this._mainEl.innerHTML = '';

    // Class preview bar
    const classPreview = document.createElement('div');
    classPreview.className = 'cc-class-preview';
    classPreview.id = 'cc-class-preview';
    classPreview.innerHTML = `
      <span class="cc-class-label">Class:</span>
      <span class="cc-class-name" id="cc-class-name">${CharacterSystem.computeClass(this._sel.trees)}</span>
      <span class="cc-tree-count" id="cc-tree-count">${this._sel.trees.length}/3 trees selected</span>
    `;
    this._mainEl.appendChild(classPreview);

    const title = document.createElement('h2');
    title.className = 'cc-step-title';
    title.textContent = 'Choose 3 Skill Trees';
    this._mainEl.appendChild(title);

    const desc = document.createElement('p');
    desc.className = 'cc-step-desc';
    desc.textContent = 'Select exactly 3 skill trees. Your class is determined by this combination.';
    this._mainEl.appendChild(desc);

    const grid = document.createElement('div');
    grid.className = 'cc-tree-grid';
    grid.id = 'cc-tree-grid';

    CharacterSystem.getSkillTrees().forEach(tree => {
      const card = document.createElement('button');
      card.type = 'button';
      const isSelected = this._sel.trees.includes(tree.id);
      const isDisabled = !isSelected && this._sel.trees.length >= 3;
      card.className = 'cc-tree-card' +
        (isSelected ? ' selected' : '') +
        (isDisabled ? ' disabled' : '');
      card.dataset.treeId = tree.id;
      card.disabled = isDisabled;
      card.innerHTML = `
        <div class="cc-tree-name">${tree.name}</div>
        <div class="cc-tree-tier ${tree.tier}">${tree.tier}</div>
        <div class="cc-tree-desc">${tree.description.slice(0, 60)}${tree.description.length > 60 ? '…' : ''}</div>
      `;
      card.addEventListener('click', () => {
        if (this._sel.trees.includes(tree.id)) {
          this._sel.trees = this._sel.trees.filter(t => t !== tree.id);
        } else if (this._sel.trees.length < 3) {
          this._sel.trees = [...this._sel.trees, tree.id];
        }
        this._rerenderTreeCards(grid);
        this._updateClassPreview();
      });
      grid.appendChild(card);
    });

    this._mainEl.appendChild(grid);
    this._updateTreesSide();
  }

  _rerenderTreeCards(grid) {
    const cards = grid.querySelectorAll('.cc-tree-card');
    cards.forEach(card => {
      const treeId = card.dataset.treeId;
      const isSelected = this._sel.trees.includes(treeId);
      const isDisabled = !isSelected && this._sel.trees.length >= 3;
      card.classList.toggle('selected', isSelected);
      card.classList.toggle('disabled', isDisabled);
      card.disabled = isDisabled;
    });
    this._updateTreesSide();
  }

  _updateClassPreview() {
    const nameEl = document.getElementById('cc-class-name');
    const countEl = document.getElementById('cc-tree-count');
    if (nameEl) nameEl.textContent = CharacterSystem.computeClass(this._sel.trees);
    if (countEl) countEl.textContent = `${this._sel.trees.length}/3 trees selected`;
  }

  _updateTreesSide() {
    this._sideEl.innerHTML = '';
    const title = document.createElement('div');
    title.className = 'cc-preview-title';
    title.textContent = 'Selected Trees';
    this._sideEl.appendChild(title);

    if (this._sel.trees.length === 0) {
      const hint = document.createElement('p');
      hint.style.cssText = 'font-size:0.75rem; color:#5a4a2a;';
      hint.textContent = 'Select 3 skill trees to determine your class.';
      this._sideEl.appendChild(hint);
      return;
    }

    const allTrees = CharacterSystem.getSkillTrees();
    this._sel.trees.forEach((treeId, i) => {
      const tree = allTrees.find(t => t.id === treeId);
      if (!tree) return;
      const el = document.createElement('div');
      el.className = 'cc-preview-trait';
      el.innerHTML = `
        <div class="cc-preview-trait-name">${i + 1}. ${tree.name}</div>
        <div class="cc-preview-trait-desc">${tree.description.slice(0, 80)}…</div>
      `;
      this._sideEl.appendChild(el);
    });

    if (this._sel.trees.length === 3) {
      const className = CharacterSystem.computeClass(this._sel.trees);
      const classBanner = document.createElement('div');
      classBanner.style.cssText = 'margin-top:12px; padding:8px; background:rgba(200,160,32,0.1); border:1px solid rgba(200,160,32,0.3); border-radius:4px; text-align:center;';
      classBanner.innerHTML = `<div style="font-size:0.7rem; color:#8a7a50; margin-bottom:2px;">CLASS</div><div style="font-size:1rem; color:#e8c040; font-weight:700;">${className}</div>`;
      this._sideEl.appendChild(classBanner);
    }
  }

  // ── Step 6: Starting Feat ─────────────────────────────────────────────────

  _renderFeatStep() {
    this._mainEl.innerHTML = `
      <h2 class="cc-step-title">Starting Feat</h2>
      <p class="cc-step-desc">Choose one feat to start with.</p>
    `;

    const grid = document.createElement('div');
    grid.className = 'cc-feat-grid';

    STARTING_FEATS.forEach(feat => {
      const card = document.createElement('button');
      card.type = 'button';
      card.className = 'cc-feat-card' + (this._sel.feat === feat.id ? ' selected' : '');
      card.innerHTML = `
        <div class="cc-feat-name">${feat.name}</div>
        <div class="cc-feat-desc">${feat.description}</div>
      `;
      card.addEventListener('click', () => {
        this._sel.feat = feat.id;
        grid.querySelectorAll('.cc-feat-card').forEach(c => c.classList.remove('selected'));
        card.classList.add('selected');
        this._updateFeatSide(feat);
      });
      grid.appendChild(card);
    });

    this._mainEl.appendChild(grid);

    const selFeat = STARTING_FEATS.find(f => f.id === this._sel.feat);
    if (selFeat) this._updateFeatSide(selFeat);
    else this._sideEl.innerHTML = `<div class="cc-preview-title">Feat Details</div><p style="font-size:0.75rem; color:#5a4a2a;">Select a feat to see details.</p>`;
  }

  _updateFeatSide(feat) {
    this._sideEl.innerHTML = '';
    const title = document.createElement('div');
    title.className = 'cc-preview-title';
    title.textContent = feat.name;
    this._sideEl.appendChild(title);

    const desc = document.createElement('p');
    desc.style.cssText = 'font-size:0.78rem; color:#7a6a40;';
    desc.textContent = feat.description;
    this._sideEl.appendChild(desc);
  }

  // ── Step 7: Confirm ───────────────────────────────────────────────────────

  _renderConfirmStep() {
    this._mainEl.innerHTML = `
      <h2 class="cc-step-title">Confirm Hero</h2>
      <p class="cc-step-desc">Review your choices before creating your hero.</p>
    `;

    const race = CharacterSystem.getRace(this._sel.raceId);
    const className = CharacterSystem.computeClass(this._sel.trees);
    const allTrees = CharacterSystem.getSkillTrees();

    const grid = document.createElement('div');
    grid.className = 'cc-confirm-grid';

    const sections = [
      {
        title: 'Identity',
        content: `
          <div class="cc-confirm-value"><strong>${this._sel.name || 'Unnamed'}</strong></div>
          <div style="font-size:0.78rem; color:#8a7a50; margin-top:4px;">${race?.name ?? '—'} &bull; ${race?.rarity ?? ''}</div>
          <div class="cc-confirm-class" style="margin-top:6px;">${className}</div>
        `,
      },
      {
        title: 'Skill Trees',
        content: this._sel.trees
          .map(tid => allTrees.find(t => t.id === tid))
          .filter(Boolean)
          .map(t => `<div class="cc-confirm-value">${t.name}</div>`)
          .join('') || '<div class="cc-confirm-value" style="color:#5a4a2a;">None selected</div>',
      },
      {
        title: 'Background',
        content: `
          <div style="font-size:0.78rem; color:#8a7a50;">Childhood</div>
          <div class="cc-confirm-value">${CHILDHOOD_BACKGROUNDS.find(b => b.id === this._sel.childhood)?.name ?? '—'}</div>
          <div style="font-size:0.78rem; color:#8a7a50; margin-top:6px;">Adult</div>
          <div class="cc-confirm-value">${ADULT_BACKGROUNDS.find(b => b.id === this._sel.adult)?.name ?? '—'}</div>
        `,
      },
      {
        title: 'Starting Feat',
        content: `<div class="cc-confirm-value">${STARTING_FEATS.find(f => f.id === this._sel.feat)?.name ?? '—'}</div>`,
      },
    ];

    sections.forEach(s => {
      const sec = document.createElement('div');
      sec.className = 'cc-confirm-section';
      sec.innerHTML = `<div class="cc-confirm-section-title">${s.title}</div>${s.content}`;
      grid.appendChild(sec);
    });

    this._mainEl.appendChild(grid);

    // Side: full attr summary
    this._sideEl.innerHTML = '';
    const sidTitle = document.createElement('div');
    sidTitle.className = 'cc-preview-title';
    sidTitle.textContent = 'Attributes';
    this._sideEl.appendChild(sidTitle);

    if (race) {
      const freeBonus = {};
      if (this._sel.freeAttrTarget) freeBonus[this._sel.freeAttrTarget] = 1;
      const attrs = ['might','agility','intellect','wisdom','endurance','presence'];
      attrs.forEach(k => {
        const base = race.baseAttributes[k] ?? 10;
        const bonus = (race.attributeBonuses ?? {})[k] ?? 0;
        const free = freeBonus[k] ?? 0;
        const total = base + bonus + free;
        const mod = CharacterSystem.getAttributeModifier(total);
        const row = document.createElement('div');
        row.className = 'cc-attr-row';
        row.innerHTML = `
          <span class="cc-attr-label">${k.charAt(0).toUpperCase() + k.slice(1)}</span>
          <span class="cc-attr-val">${total} (${mod >= 0 ? '+' : ''}${mod})</span>
        `;
        this._sideEl.appendChild(row);
      });
    }
  }

  // ── Create Hero ───────────────────────────────────────────────────────────

  _createHero() {
    const race = CharacterSystem.getRace(this._sel.raceId);
    const freeBonus = {};
    if (this._sel.freeAttrTarget) freeBonus[this._sel.freeAttrTarget] = 1;

    const baseAttrs = this._sel.attributes ?? this._computeRaceAttributes(race);
    const finalAttrs = {};
    for (const k of Object.keys(baseAttrs)) {
      finalAttrs[k] = baseAttrs[k] + (freeBonus[k] ?? 0);
    }

    const hero = CharacterSystem.createHero({
      name: this._sel.name?.trim() || 'Hero',
      raceId: this._sel.raceId,
      attributeOverrides: finalAttrs,
      appearance: {
        bodyType: this._sel.bodyType,
        skinColor: this._sel.skinColor,
        hairColor: this._sel.hairColor,
        eyeColor:  this._sel.eyeColor,
      },
      background: {
        childhood: this._sel.childhood ?? 'farmer',
        adult:     this._sel.adult ?? 'soldier',
      },
      skillTrees:   this._sel.trees,
      startingFeat: this._sel.feat,
      alignment:    'neutral',
    });

    DebugLog.info(`[party] CharCreate complete; heroId=${hero.id} name=${hero.name} class=${hero.class}`);

    if (this._onComplete) this._onComplete(hero);
  }

  // ── Keyboard ───────────────────────────────────────────────────────────────

  _onKey(e) {
    if (!this._visible) return;
    if (e.key === 'Escape') {
      // No-op on charCreate (can't leave without completing)
      e.preventDefault();
    }
  }

  // ── Destroy ────────────────────────────────────────────────────────────────

  destroy() {
    document.removeEventListener('keydown', this._keyHandler);
    super.destroy();
  }
}

// ─── CharCreateScene ──────────────────────────────────────────────────────────

export default class CharCreateScene {
  constructor() {
    this._panel = null;
  }

  async init() {
    DebugLog.info('[boot] CharCreateScene init');

    injectStyles();

    // Expose on __debug
    if (!window.__debug) window.__debug = {};
    window.__debug.currentScene = 'charCreate';

    this._panel = new CharCreatePanel((hero) => {
      // Hero created — pass to party builder
      SceneManager.transition('partyBuilder', { heroes: [hero] });
    });

    this._panel.build();
    this._panel.show();

    DebugLog.info('[boot] CharCreateScene ready');
  }

  update(_dt) {}

  async destroy() {
    DebugLog.info('[boot] CharCreateScene destroy');
    if (this._panel) {
      this._panel.destroy();
      this._panel = null;
    }
    if (window.__debug && window.__debug.currentScene === 'charCreate') {
      window.__debug.currentScene = null;
    }
  }
}
